package com.court.assistant.webview

import android.graphics.Bitmap
import android.webkit.WebResourceRequest
import android.webkit.WebView
import android.webkit.WebViewClient

class CourtWebViewClient(
    private val onPdfDetected: (url: String) -> Unit,
    private val onPageLoaded: () -> Unit
) : WebViewClient() {

    override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
        val url = request?.url?.toString() ?: return false
        if (isPdfUrl(url)) {
            onPdfDetected(url)
            return true
        }
        return false
    }

    override fun onPageFinished(view: WebView?, url: String?) {
        super.onPageFinished(view, url)
        onPageLoaded()
    }

    private fun isPdfUrl(url: String): Boolean {
        val lower = url.lowercase()
        return lower.endsWith(".pdf") || lower.contains(".pdf?") || lower.contains("getpdf")
    }
}
