@OptIn(ExperimentalMaterial3Api::class)
@SuppressLint("SetJavaScriptEnabled")
@Composable
fun WebViewScreen(
    viewModel: MainViewModel,
    smsId: Long,
    url: String,
    onBack: () -> Unit
) {
    val state by viewModel.uiState.collectAsState()
    val snackbarHostState = remember { SnackbarHostState() }
    val scope = rememberCoroutineScope()
    var loading by remember { mutableStateOf(true) }
    var showBackDialog by remember { mutableStateOf(false) }

    LaunchedEffect(Unit) {
        viewModel.resetDownloadCount()
        viewModel.downloadEvent.collect { msg ->
            snackbarHostState.showSnackbar(msg, duration = SnackbarDuration.Short)
        }
    }

    if (showBackDialog && state.downloadCount > 0) {
        AlertDialog(
            onDismissRequest = { showBackDialog = false },
            title = { Text("下载完成") },
            text = { Text("已下载 ${state.downloadCount} 个文书，确认返回？") },
            confirmButton = {
                TextButton(onClick = {
                    showBackDialog = false
                    viewModel.resetDownloadCount()
                    onBack()
                }) { Text("返回", color = CinnabarRed) }
            },
            dismissButton = {
                TextButton(onClick = { showBackDialog = false }) { Text("继续下载") }
            }
        )
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            TopAppBar(
                title = { Text("文书送达", style = MaterialTheme.typography.titleLarge) },
                navigationIcon = {
                    IconButton(onClick = {
                        if (state.downloadCount > 0) showBackDialog = true else onBack()
                    }) {
                        Icon(Icons.Default.ArrowBack, contentDescription = "返回")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = Ivory,
                    titleContentColor = InkBlack
                )
            )
        }
    ) { padding ->
        Column(modifier = Modifier.fillMaxSize().padding(padding)) {
            // 提示条
            Surface(
                color = AmberGold.copy(alpha = 0.15f),
                modifier = Modifier.fillMaxWidth()
            ) {
                Row(
                    modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        "请点击文书下载，完成后自动保存",
                        style = MaterialTheme.typography.labelLarge,
                        color = CharcoalGray
                    )
                    if (state.downloadCount > 0) {
                        Surface(
                            color = JadeGreen,
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Text(
                                " ${state.downloadCount} 已下载 ",
                                style = MaterialTheme.typography.labelSmall,
                                color = WarmWhite,
                                modifier = Modifier.padding(horizontal = 8.dp, vertical = 2.dp)
                            )
                        }
                    }
                }
            }

            // Loading indicator
            if (loading) {
                LinearProgressIndicator(
                    modifier = Modifier.fillMaxWidth(),
                    color = CinnabarRed
                )
            }

            // WebView
            AndroidView(
                modifier = Modifier.fillMaxSize(),
                factory = { context ->
                    WebView(context).apply {
                        layoutParams = ViewGroup.LayoutParams(
                            ViewGroup.LayoutParams.MATCH_PARENT,
                            ViewGroup.LayoutParams.MATCH_PARENT
                        )
                        settings.apply {
                            javaScriptEnabled = true
                            domStorageEnabled = true
                            useWideViewPort = true
                            loadWithOverviewMode = true
                            allowFileAccess = true
                            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
                            userAgentString = settings.userAgentString.replace("wv", "")
                        }

                        webViewClient = CourtWebViewClient(
                            onPdfDetected = { pdfUrl ->
                                val cookies = CookieManager.getInstance().getCookie(pdfUrl)
                                viewModel.downloadPdf(pdfUrl, smsId, cookies = cookies)
                            },
                            onPageLoaded = { loading = false }
                        )

                        webChromeClient = object : WebChromeClient() {
                            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                                if (newProgress >= 100) loading = false
                            }
                        }

                        setDownloadListener { downloadUrl, userAgent, contentDisposition, mimetype, contentLength ->
                            val cookies = CookieManager.getInstance().getCookie(downloadUrl)
                            // 从 Content-Disposition 提取文件名
                            val fileName = parseContentDispositionFileName(contentDisposition)
                            viewModel.downloadPdf(downloadUrl, smsId, fileName, cookies)
                        }

                        loadUrl(url)
                    }
                }
            )
        }
    }
}

private fun parseContentDispositionFileName(contentDisposition: String?): String? {
    if (contentDisposition == null) return null
    Regex("filename\\*=(?:UTF-8''|utf-8'')(.+)").find(contentDisposition)?.let {
        return try { java.net.URLDecoder.decode(it.groupValues[1], "UTF-8") } catch (_: Exception) { null }
    }
    Regex("filename=\"?([^\"]+)\"?").find(contentDisposition)?.let {
        return it.groupValues[1].trim()
    }
    return null
}
