private fun parseContentDispositionFileName(contentDisposition: String?): String? {
    if (contentDisposition == null) return null
    Regex("filename\*=(?:UTF-8''|utf-8'')(.+)").find(contentDisposition)?.let {
        return try { java.net.URLDecoder.decode(it.groupValues[1], "UTF-8") } catch (_: Exception) { null }
    }
    Regex("filename=\"?([^\"]+)\"?").find(contentDisposition)?.let {
        return it.groupValues[1].trim()
    }
    return null
